mapper.select:
SELECT s.our_company_name AS ourCompanyName, s.company_name AS companyName, SUM(IFNULL(s.total_number,0)) AS tradeTonnes, SUM(IFNULL(s.total_amount,0)) AS totalAmount, COUNT(*) AS tradeCount, SUM(IFNULL(s.total_amount,0) - IFNULL(s.dealed_amount,0)) AS receivablePrincipal, SUM(IFNULL(s.breach_amount,0) - IFNULL(s.receive_breach_amount,0)) AS receivableBreachAmount FROM t_ctr_contract s INNER JOIN t_ctr_contract_settlement r ON s.id = r.sell_contract_id INNER JOIN t_ctr_contract b ON b.id = r.buy_contract_id WHERE s.enterprise_id = 44 AND s.business_type = 'ZY-BB' AND s.contract_type = 'S' AND s.special_chain_flag = FALSE AND s.contract_status != 'C' AND b.contract_status != 'C' AND s.seal_flg = TRUE AND b.seal_flg = TRUE AND (IFNULL(s.total_amount,0) - IFNULL(s.dealed_amount,0) > 0 OR IFNULL(s.breach_amount,0) - IFNULL(s.receive_breach_amount,0) > 0 )
AND s.our_company_name = #{ourCompanyName}
and s.company_name LIKE CONCAT('%',#{companyName},'%')
and s.our_company_name IN
#{ourCompanyNameList[${index}],jdbcType=VARCHAR}
and s.match_user_id not in
#{hgMatchUserIdList[${index}]}
and s.match_user_id in
#{hgMatchUserIdList[${index}]}
GROUP BY s.our_company_name, s.company_name ORDER BY s.our_company_name DESC

SELECT s.id AS id, s.contract_no AS contractNo, s.business_type AS businessType, s.match_credit_flg AS matchCreditFlg, s.products_name as productName, s.match_user_id as matchUserId, s.match_user_name as matchUserName, s.dept_id as deptId, s.seal_date as sealDate, s.our_company_name AS ourCompanyName, s.company_name AS companyName, IFNULL(s.total_number,0) AS tradeTonnes, IFNULL(s.total_amount,0) AS totalAmount, IFNULL(s.dealed_amount,0) AS dealedAmount, IFNULL(s.total_amount,0) - IFNULL(s.dealed_amount,0) AS receivablePrincipal, IFNULL(s.breach_amount,0) AS breachAmount, IFNULL(s.receive_breach_amount,0) AS receiveBreachAmount, IFNULL(s.breach_amount,0) - IFNULL(s.receive_breach_amount,0) AS receivableBreachAmount FROM t_ctr_contract s INNER JOIN t_ctr_contract_settlement r ON s.id = r.sell_contract_id INNER JOIN t_ctr_contract b ON b.id = r.buy_contract_id WHERE s.enterprise_id = 44 AND s.business_type = 'ZY-BB' AND s.contract_type = 'S' AND s.special_chain_flag = FALSE AND s.contract_status != 'C' AND b.contract_status != 'C' AND s.seal_flg = TRUE AND b.seal_flg = TRUE AND (IFNULL(s.total_amount,0) - IFNULL(s.dealed_amount,0) > 0 OR IFNULL(s.breach_amount,0) - IFNULL(s.receive_breach_amount,0) > 0 )
AND s.our_company_name = #{ourCompanyName}
and s.company_name LIKE CONCAT('%',#{companyName},'%')
and s.our_company_name IN
#{ourCompanyNameList[${index}],jdbcType=VARCHAR}
and s.match_user_id not in
#{hgMatchUserIdList[${index}]}
and s.match_user_id in
#{hgMatchUserIdList[${index}]}
ORDER BY s.id DESC

SELECT SUM(IFNULL(s.total_number,0)) AS tradeTonnes, SUM(IFNULL(s.total_amount,0)) AS totalAmount, COUNT(*) AS tradeCount, SUM(IFNULL(s.dealed_amount,0)) AS dealedAmount, SUM(IFNULL(s.total_amount,0) - IFNULL(s.dealed_amount,0)) AS receivablePrincipal, SUM(IFNULL(s.breach_amount,0)) AS breachAmount, SUM(IFNULL(s.receive_breach_amount,0)) AS receiveBreachAmount, SUM(IFNULL(s.breach_amount,0) - IFNULL(s.receive_breach_amount,0)) AS receivableBreachAmount FROM t_ctr_contract s INNER JOIN t_ctr_contract_settlement r ON s.id = r.sell_contract_id INNER JOIN t_ctr_contract b ON b.id = r.buy_contract_id WHERE s.enterprise_id = 44 AND s.business_type = 'ZY-BB' AND s.contract_type = 'S' AND s.special_chain_flag = FALSE AND s.contract_status != 'C' AND b.contract_status != 'C' AND s.seal_flg = TRUE AND b.seal_flg = TRUE AND (IFNULL(s.total_amount,0) - IFNULL(s.dealed_amount,0) > 0 OR IFNULL(s.breach_amount,0) - IFNULL(s.receive_breach_amount,0) > 0 )
AND s.our_company_name = #{ourCompanyName}
and s.company_name LIKE CONCAT('%',#{companyName},'%')
and s.our_company_name IN
#{ourCompanyNameList[${index}],jdbcType=VARCHAR}
and s.match_user_id not in
#{hgMatchUserIdList[${index}]}
and s.match_user_id in
#{hgMatchUserIdList[${index}]}
